var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……이제 됐어요. 더 이상 낭비할 시간 없습니다.","JPN":"……もういいですわ。これ以上時間を無駄遣いするわけにはいきません。","ENG":"...Enough with this. I do not wish to waste any more time.","TWN":"……現在可以了，我沒有時間可以浪費了。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델의 위치나 말하세요. 당신이라면 알고 있을 거라더군요.","JPN":"エデルの位置を教えてください。あなたなら知っていると聞きました。","ENG":"Tell me where Edel is. I heard you will know her whereabouts.","TWN":"請告訴我艾瑟兒的位置。你一定知道吧。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"물론 말씀드릴 수 있습니다.","JPN":"もちろんお教えできます。","ENG":"Yes, I do. And I can tell you.","TWN":"當然，我可以告訴你。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"하지만 그 전에, 한 가지 충고해 드리죠.","JPN":"ですがその前に、一つだけ忠告しましょう。","ENG":"But first, please allow me to offer you some advice.","TWN":"只是在那之前，我要給你一個忠告。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"얘기해 보세요. 받아들일지는 들은 다음에 결정하겠습니다.","JPN":"どうぞ。受け入れるかどうかは、聞いてから決めますわ。","ENG":"Continue. I will decide whether to heed your advice after I hear it.","TWN":"你說說看。聽完之後我再決定是否接受。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"학회장님의 선의를 믿으십시오.","JPN":"学会長の善意を信頼してください。","ENG":"Trust the President's good intentions.","TWN":"請相信學會長的善意。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"선의라고요?","JPN":"善意ですって？","ENG":"Good intentions?","TWN":"善意？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"회동이 끝난 뒤 안정을 위해 휴가를 떠나셨죠. 기억하십니까?","JPN":"会合が終わった後、安静のために休暇を取られましたね。覚えていますか？","ENG":"You went on vacation after the meeting to unwind. Do you recall?","TWN":"會議結束後，你為了放鬆去休假了。你還記得吧？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……네. 기억나요. 리벳이 골라 준 의상을 입고 무대에 서느라 고생했죠.","JPN":"……はい。覚えています。リベットが選んでくれた衣装を着てステージに立つのに苦労しました。","ENG":"...Yes. I remember struggling on stage in the dress Rivet had chosen for me.","TWN":"……是，我記得。穿著里維給我挑的衣服站在舞台上，我還吃了不少苦頭。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그 곳에서 맥크레디 양은 공교롭게도 마왕의 사도와 조우하셨습니다.","JPN":"そこでマクレディーさんはあいにく、魔王の使徒と遭遇してしまいました。","ENG":"There, you coincidentally encountered the Demon Lord's Apostle.","TWN":"在那裡，麥克蕾蒂碰巧遇到了魔王的使徒。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"꼭두각시처럼 조종당하다 몸 속에 있던 마지막 한 방울의 힘까지 빼앗기시고 말았죠.","JPN":"操り人形のように操縦され、体の中に残っていた最後の力まで奪われてしまったのです。","ENG":"You were manipulated like a puppet, and every ounce of strength was taken from you.","TWN":"你像傀儡一樣被操控，被奪走了身體裡的最後一絲力量。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"인형의 주인이 저지른 짓이었지. 결과적으로는 자충수였지만.","JPN":"人形の持ち主の仕業だったな。結果的には自滅して終わったが。","ENG":"The Puppet Master was behind it. But it was ultimately a blunder on her part.","TWN":"那事是人偶的主人幹的。不過最後它自食惡果了。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"사장님도…… 그 때 일을 알고 계셨나요?","JPN":"社長も……その時のことをご存じだったのですか？","ENG":"Boss... Did you also know about this?","TWN":"老闆……也知道當時的事嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇지. 불완전한 가아그셰블라가 본체를 현현했을 정도이니 말일세.","JPN":"ああ。不完全なガアグシェブラが本体を現したくらいだったからね。","ENG":"Yes. It was enough for an imperfect embodiment of Gha'agsheblah to manifest.","TWN":"是的。不完整的加瓦格夫拉甚至還顯現出了本體。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"역시 지켜보고 계셨군요.","JPN":"やはり見ていらしたのですね。","ENG":"I knew you were watching it.","TWN":"你果然在看著呢。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"언젠가 당신과 마주앉아 담소를 나눌 날을 기다리고 있었습니다.","JPN":"あなたと向かい合い、なごやかに会話できる日をずっと待ち望んでいました。","ENG":"I have been waiting for a day like this to sit down and have a chat with you.","TWN":"我等著能和你面對面地坐著聊天的那一天。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"이 나이에 황홀경이라는 것을 겪을 줄은 몰랐군요.","JPN":"この年になって恍惚の境地というものを経験するとは。","ENG":"I never imagined I'd be experiencing something called rapture at this age.","TWN":"沒想到這個年紀的我還會經歷這種激動人心的時刻。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"당신과 대화하고 있다는 사실을 자각하는 매순간마다…… 전율마저 느껴집니다.","JPN":"あなたと話していることを自覚するたびに……戦慄さえ覚えてしまいます。","ENG":"Every time I realize that I am talking to you... shivers run down my spine.","TWN":"意識到我正在跟你交談的每個瞬間……我都能感受到顫慄。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 기쁨은 다음으로 남겨 두게나. 다시 기회를 얻긴 그리 쉽지 않겠네만.","JPN":"その喜びは後の楽しみに取って置きたまえ。そう簡単に次の機会は訪れないだろうがね。","ENG":"Let's save that joy for some other time. Although I'm not sure if there will be another chance.","TWN":"那種喜悅你還是留到下次吧。不過你應該不那麼容易再得到機會了。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"참으로 아쉬운 노릇이지요. 학술적인 교류마저 입장차 때문에 저해된다는 것은.","JPN":"実に残念なかぎりです。学術的な交流でさえも、立場の違いのせいで阻害されてしまう。","ENG":"It truly is a pity. That even academic discussions are hampered by ideological differences.","TWN":"真讓人遺憾。連學術交流，也會因為立場不同而受阻啊。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"맥크레디 양, 학회장님께서 그렇게 분개하신 적은 그 날이 처음이자 마지막이었습니다.","JPN":"マクレディーさん、学会長があれほど憤慨なさったのは、その日が最初で最後でした。","ENG":"Ms. MacCready, it was the first and last time the President was enraged that much.","TWN":"麥克蕾蒂，那天是學會長第一次、也是最後一次那麼憤怒。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그것만으로 선의라고 단정할 수 있나요?","JPN":"それだけで善意と断定できるのですか？","ENG":"Are you saying I should trust her based on just that?","TWN":"僅憑這一點就可以斷定是善意嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"기르는 애완동물 때문에 화내는 사람도 존재합니다. 선의인지 소유욕인지…….","JPN":"飼っていたペットのために怒る人もいますわ。善意なのか所有欲なのか……","ENG":"There are people who get angry at their pets. How would you know...","TWN":"也有人會因為養的寵物而生氣。究竟是善意還是佔有欲……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"자기 재산인 가축이 상해서 기분 나쁜 건지 어떻게 알죠?","JPN":"それとも、自分の財産である家畜が傷つけられて気分が悪いのか、どうやってわかるのですか？","ENG":"If it was out of good intentions, possessiveness, or just lashing because their livestock was damaged?","TWN":"還是因為作為自己財產的家畜受傷了而心情不好，怎樣才能知道呢？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"애완동물이면 어떻고 가축이면 어떻습니까?","JPN":"ペットか家畜かは大した差ではありません。","ENG":"What does it matter if it's a pet or a livestock?","TWN":"寵物怎麼了，家畜又怎麼了？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"중요한 건 맥크레디 양이 이제까지 학회를 거쳐 간 어느 누구보다 호수의 근원에 접근했다는 사실입니다.","JPN":"重要なのはマクレディーさんが今まで学会に係わった誰よりも、湖の根源に近づいたという事実です。","ENG":"The important thing is that you got closer to the source of the Lake than anyone else in the Society.","TWN":"重要的是，麥克蕾蒂是迄今為止學會裡最接近湖水之源的人。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_B","text":{"KOREA":"교수님, 브로커에게서 연락이 왔습니다. 지금 방공호 근처라고 합니다.","JPN":"教授、ブローカーから連絡がありました。今、防空壕の近くにいるようです。","ENG":"Professor, I got word back from the broker. He says he is nearby.","TWN":"教授，偷渡掮客來電話了，說是現在在防空洞附近。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"이제 헤어질 시간이군요. 맥크레디 양.","JPN":"もうお別れの時間ですね、マクレディーさん。","ENG":"It's time to say goodbye, Ms. MacCready.","TWN":"現在也該分開了，麥克蕾蒂。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"먼저 가십시오. 저는 뒤따라 가겠습니다.","JPN":"お先にどうぞ。私は後からついていきます。","ENG":"Please, go ahead. I'll be right behind you.","TWN":"你先走吧，我會隨後趕過去的。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이제 와서 챙겨 주는 척 하는 건가요?","JPN":"今更気を遣うふりですか？","ENG":"Why are you pretending to care about me now?","TWN":"現在才裝出一副照顧我的樣子嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그래 봐야 당신에 대한 제 인식은 변하지 않습니다.","JPN":"それでもあなたに対する私の認識は変わりません。","ENG":"You know just as well that it will not change how I think about you.","TWN":"即便如此，我對你的認識也不會改變。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"챙겨 준다……","JPN":"気を遣う、ですか……","ENG":"\\"Care about you\\"? Hmm...","TWN":"照顧你……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"오해하지 마세요. 저는 그저 당신에게 기대를 걸었을 뿐입니다.","JPN":"誤解しないでほしいですね。私はただ、あなたに期待しているだけです。","ENG":"Don't be mistaken. I merely have high hopes for you.","TWN":"別誤會。我只是對你寄予厚望而已。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"가시죠, 어서. 곧 기관이 들이닥칠 겁니다.","JPN":"早く行ってください。もうすぐ機関が押しかけてくるでしょう。","ENG":"We should go. The Institution could come at any minute.","TWN":"快走吧，機關的人就要追過來了。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};